changeSet.sql:
CREATE TABLE agent_profile ( id BIGSERIAL PRIMARY KEY, code VARCHAR(64) NOT NULL UNIQUE, name VARCHAR(128) NOT NULL, description VARCHAR(1000), created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE agent_profile_version ( id BIGSERIAL PRIMARY KEY, profile_id BIGINT NOT NULL REFERENCES agent_profile(id), version_number INTEGER NOT NULL, status VARCHAR(16) NOT NULL, chat_model VARCHAR(64) NOT NULL, embedding_model VARCHAR(64) NOT NULL, rerank_model VARCHAR(64), temperature DOUBLE PRECISION NOT NULL, retrieval_top_k INTEGER NOT NULL, reasoning_budget INTEGER NOT NULL, published BOOLEAN NOT NULL DEFAULT FALSE, system_prompt TEXT NOT NULL, tool_bindings TEXT NOT NULL, mcp_bindings TEXT NOT NULL, skill_bindings TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE INDEX idx_agent_profile_version_profile ON agent_profile_version(profile_id); CREATE INDEX idx_agent_profile_version_published ON agent_profile_version(published);

CREATE TABLE knowledge_document ( id BIGSERIAL PRIMARY KEY, title VARCHAR(128) NOT NULL, source_filename VARCHAR(256) NOT NULL, status VARCHAR(16) NOT NULL, normalized_markdown_path VARCHAR(256) NOT NULL, tags TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE document_asset ( id BIGSERIAL PRIMARY KEY, document_id BIGINT NOT NULL REFERENCES knowledge_document(id), original_path VARCHAR(512) NOT NULL, stored_url VARCHAR(512) NOT NULL, content_type VARCHAR(128), created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE document_chunk ( id BIGSERIAL PRIMARY KEY, document_id BIGINT NOT NULL REFERENCES knowledge_document(id), chunk_index INTEGER NOT NULL, heading_path VARCHAR(512) NOT NULL, anchor VARCHAR(128) NOT NULL, content TEXT NOT NULL, metadata_json TEXT NOT NULL, embedding vector(1024), created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE ingestion_job ( id BIGSERIAL PRIMARY KEY, document_id BIGINT NOT NULL REFERENCES knowledge_document(id), status VARCHAR(16) NOT NULL, job_type VARCHAR(64) NOT NULL, detail TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE INDEX idx_document_chunk_document ON document_chunk(document_id); CREATE INDEX idx_document_chunk_anchor ON document_chunk(anchor); CREATE INDEX idx_document_chunk_tsv ON document_chunk USING GIN (to_tsvector('simple', content));

CREATE TABLE tool_definition ( id BIGSERIAL PRIMARY KEY, code VARCHAR(64) NOT NULL UNIQUE, name VARCHAR(128) NOT NULL, input_schema TEXT NOT NULL, endpoint VARCHAR(256) NOT NULL, enabled BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE mcp_server ( id BIGSERIAL PRIMARY KEY, code VARCHAR(64) NOT NULL UNIQUE, transport_type VARCHAR(32) NOT NULL, target VARCHAR(256) NOT NULL, capabilities_json TEXT NOT NULL, enabled BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE skill_binding ( id BIGSERIAL PRIMARY KEY, code VARCHAR(64) NOT NULL UNIQUE, name VARCHAR(128) NOT NULL, prompt_template TEXT NOT NULL, enabled BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );

CREATE TABLE webhook_subscription ( id BIGSERIAL PRIMARY KEY, event_type VARCHAR(32) NOT NULL, target_url VARCHAR(256) NOT NULL, secret_masked VARCHAR(128) NOT NULL, enabled BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE hook_delivery ( id BIGSERIAL PRIMARY KEY, event_type VARCHAR(32) NOT NULL, target_url VARCHAR(256) NOT NULL, attempt_count INTEGER NOT NULL DEFAULT 0, status VARCHAR(16) NOT NULL, payload_json TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE chat_session ( id BIGSERIAL PRIMARY KEY, session_code VARCHAR(64) NOT NULL UNIQUE, active_profile_code VARCHAR(32) NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE agent_trace ( id BIGSERIAL PRIMARY KEY, trace_code VARCHAR(64) NOT NULL, session_code VARCHAR(64) NOT NULL, stage VARCHAR(64) NOT NULL, payload_json TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE INDEX idx_agent_trace_session ON agent_trace(session_code);

